module div_16bit(
    input [15:0] A,
    input [7:0] B,
    output [15:0] result,
    output [15:0] odd
);

    reg [15:0] dividend;
    reg [7:0] divisor;
    reg [15:0] quotient;
    reg [15:0] remainder;

    always @(*) begin
        dividend = A[15:8];
        divisor = B;
        quotient = 16'b0;
        remainder = 16'b0;

        if (dividend >= divisor) begin
            quotient = 16'b1;
            remainder = dividend - divisor;
        end
        else begin
            quotient = 16'b0;
            remainder = dividend;
        end
    end

    assign result = quotient;
    assign odd = remainder;

endmodule
